function whirligig(x, y, angle, c1, c2) {
  push();
  translate(x, y);
  rotate(angle);
  cookie(0, 0, c1, c2); // Passing parameters down to the next function
  for (let i = 0; i < 35; i++) {
    scale(0.9);
    rotate(45);
    cookie(0, 0, c1, c2);
  }
  pop();
}

let offset = 0;
// ... in draw()
whirligig(noise(offset) * width, noise(offset + 10) * height, ...);
offset += 0.01;
